import boto3

def send_sqs_message(queue_url, user_data):
    sqs = boto3.client('sqs')

    response = sqs.send_message(
        QueueUrl=queue_url,
        MessageBody=user_data
    )

    return response

# Example usage
user_data = {
    'email': 'user@example.com',
    'phone_number': '123-456-7890',
    'address': '123 Main St, Anytown, USA'
}

send_sqs_message('https://sqs.us-east-1.amazonaws.com/123456789012/MyQueue', str(user_data))